import { ReactComponent } from '*.svg';
import ExpenseItem from './Components/ExpenseItem';

function App() {
  const item_list = [
    {
      date: "24-05-2021",
      title: "SleepWell Bed",
      amount: 12499
    },
    {
      date: "23-05-2021",
      title: "Antidandruff shampoo",
      amount: 349
    },
    {
      date: "20-05-2021",
      title: "Castor oil",
      amount: 150
    },
    {
      date: "20-05-2021",
      title: "Badam",
      amount: 750
    },
  ];
  return (
    <div className="App">
      <h2>Let's get started!</h2>
      <ExpenseItem date = "24-02-2021" title = "Sleepwell Bed" price = {12000}></ExpenseItem>
    </div>
  );
}

export default App;
